import { execution } from '@dynatrace-sdk/automation-utils';
export default async function ({ execution_id }) {
  const configGet = await fetch(`/platform/automation/v1/executions/${execution_id}/tasks/wait-for-completion/result`);
  const configBody = await configGet.json();
  if (configBody.AutomationExecutionStatus !== "Success") throw new Error("Instance launch failed!");
  return configBody;
}
